VALUES
  ('police-8b7f1efc-moex-00667', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '民主法治社會，為避免警察權濫用，仍需要相當的制衡機制，下列有關敘述，何者錯誤？', '["立法部門儘量明定警察職權範圍與界限", "司法部門對警察違法審查救濟機制，程序簡化，審期加速", "行政部門加強警察人員培訓，服從領導指令，貫徹執行命令", "警察機關嚴格實踐正當程序要求，強化內部監控功能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00668', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', 'Svara 綜合規範倫理學的重要理論提出倫理鐵三角的衡平性看法，他認為義務論、德行論和效益 論等三種不同的倫理學理論，分別強調倫理鐵三角的重要性，所指倫理鐵三角是下列何者？', '["規則、德行、結果", "規則、過程、結果", "程序、德行、過程", "程序、規則、德行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00669', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '司法院釋字第535號解釋，是審查有關警察實施臨檢、盤查權所依據的警察勤務條例規定合憲性 的案件，警察行使該項職權，可能涉及人民一項或多項的自由與權利，是影響層面廣泛的憲法議 題；有關司法院釋字第535號解釋的敘述，下列何者正確？', '["司法院釋字第535號解釋與司法院釋字第445號解釋，皆採用重要關聯性理論受理審查並作出 解釋", "警察勤務條例為單純之組織法，其有關臨檢之規定，不能作為員警任意臨檢、取締或隨機檢查、 盤查之依據", "臨檢實施之檢查、取締或盤查等，係對犯罪嫌疑人或處所之查驗、檢查，影響人民名譽權及隱 私權等甚鉅", "行政機關行使職權，不應僅以組織法之職掌規定為準，更應有職權命令作執行依據，始符合依 法行政之原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00670', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察勤務無論是現在或未來，亦或其如何變革，警察勤務在運作上，仍脫不了以下四項原理的支 配，下列有關警察勤務運作原理的敘述，何者錯誤？', '["迅速原理，其是指警察人員越早到達犯罪現場，則逮捕犯罪人的機會越大，因此，有所謂的TAP 理論的出現", "顯見原理，即見警率的歸納；亦即警察在執行勤務時，無論其服裝或裝備，都必須明顯易見， 此在傳統警察勤務觀念中，具相當意義", "彈性原理，指警察勤務運作方式上應避免一成不變，也就是勤務執行的「因時因地因事制宜」", "機動原理，這是強調動態的勤務運作而言，其基本假設是警察勤務應採被動反應式的處理問題， 而非主動先發式的發現問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00671', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依現行警察人員執行勤務著防彈衣及戴防彈頭盔規定，下列有關特殊狀況是否穿戴防彈衣防彈頭 盔的決定，何者正確？', '["執行勤區查察勤務：聯合查察及特殊狀況由帶班人員決定穿戴防彈衣及頭盔", "汽車巡邏：下車執勤時，由帶班人員視治安狀況決定穿戴防彈衣及頭盔", "徒步或腳踏車巡邏：由分局長視天候及治安狀況決定穿戴防彈衣及頭盔", "執行臨檢勤務：由分局長視臨檢對象及治安狀況決定穿戴防彈衣及頭盔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00672', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察人員升官等考試規則，下列相關敘述，何者正確？', '["警察人員升官等考試規則依據警察法第10條規定訂定之", "警察人員升官等考試，可分為警員升巡佐，巡官升警務員兩種", "警察人員陞遷，參加此項考試及格者，是唯一取得警察人員晉升職務途徑", "警察人員升官等考試總成績未達50分，或筆試科目一科成績為0分者，不予錄取"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
