  ('police-8b7f1efc-moex-00674', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察職權行使法所稱警察機關主管長官，係指何種職務以上長官？', '["警政署署長", "警察局局長", "警察分局分局長", "警察派出所所長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00675', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據警察職權行使法第2條第2項規定，下列何者非警察職權？', '["搜索、扣押", "查證身分、鑑識身分", "蒐集資料", "保管、銷毀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00676', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '司法院釋字第785號解釋有關公務人員訴訟權保障及外勤消防人員勤休方式與超勤補償案，其解 釋理由書與警消之勤休方式息息相關，該解釋有關敘述，下列何者正確？', '["公務人員服勤時間與休假制度，應受憲法工作權之保障", "超勤補償，為俸給延伸，並非恩給，應受憲法財產權之保障", "公務人員服勤時間及休假制度，屬憲法第18條保障健康權之範疇", "本號解釋不僅釋示憲法保障健康權之內涵，更首次表態釋示國家負有最低限度之保護義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
